blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie zobaczysz, jak tworzyć <strong>pytania przeczące</strong> i jak zmienia się ich znaczenie w zależności od kontekstu.",
    "rules": [
        {
            "label": "STRUKTURA",
            "color": "emerald",
            "text": "Używamy <strong>przeczącej formy czasownika pomocniczego</strong>:",
            "example": "Don't you know? / Isn't she coming?"
        },
        {
            "label": "ZNACZENIE",
            "color": "blue",
            "text": "Pytanie przeczące często wyraża <strong>zaskoczenie</strong> albo <strong>oczekiwanie</strong>:",
            "example": "Don't you like coffee?"
        },
        {
            "label": "ODPOWIEDŹ",
            "color": "amber",
            "text": "Odpowiadamy zgodnie z <strong>treścią</strong>, a nie samą formą pytania:",
            "example": "Don't you know? — Yes, I do. / No, I don't."
        }
    ]
}

{
    "title": "1. Czym są pytania przeczące?",
    "intro": "Pytania przeczące zawierają przeczącą formę czasownika pomocniczego:",
    "items": [
        {
            "label": "Pytanie zwykłe",
            "title": "Do you know?",
            "subtitle": "Pytanie neutralne"
        },
        {
            "label": "Pytanie przeczące",
            "title": "Don't you know?",
            "subtitle": "Zaskoczenie albo oczekiwanie"
        },
        {
            "label": "Efekt",
            "title": "Dodatkowy wydźwięk emocjonalny",
            "subtitle": "Mówiący pokazuje swoje nastawienie"
        }
    ]
}

{
    "title": "2. Pytania przeczące z DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "W Present Simple używamy <strong>don't</strong> albo <strong>doesn't</strong>.",
            "examples": [
                {
                    "en": "Don't you like coffee?",
                    "ua": "Czy nie lubisz kawy?"
                },
                {
                    "en": "Doesn't she work here?",
                    "ua": "Czy ona tu nie pracuje?"
                },
                {
                    "en": "Don't they know the answer?",
                    "ua": "Czy oni nie znają odpowiedzi?"
                },
                {
                    "en": "Doesn't he speak English?",
                    "ua": "Czy on nie mówi po angielsku?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "sky",
            "description": "W Past Simple dla wszystkich osób używamy <strong>didn't</strong>.",
            "examples": [
                {
                    "en": "Didn't you see the film?",
                    "ua": "Czy nie widziałeś filmu?"
                },
                {
                    "en": "Didn't she call you?",
                    "ua": "Czy ona do ciebie nie zadzwoniła?"
                },
                {
                    "en": "Didn't they arrive yesterday?",
                    "ua": "Czy oni nie przyjechali wczoraj?"
                },
                {
                    "en": "Didn't it rain last night?",
                    "ua": "Czy wczoraj w nocy nie padało?"
                }
            ]
        },
        {
            "label": "Struktura",
            "color": "purple",
            "description": "Formuła pytania przeczącego z <strong>do/does/did</strong> wygląda tak:",
            "examples": [
                {
                    "en": "Don't/Doesn't/Didn't + subject + verb (base form) + ...?",
                    "ua": "Don't/Doesn't/Didn't + podmiot + czasownik w formie podstawowej + ...?"
                }
            ],
            "note": "📌 Po <strong>didn't</strong> główny czasownik pozostaje w formie podstawowej."
        }
    ]
}

{
    "title": "3. Pytania przeczące z TO BE",
    "sections": [
        {
            "label": "Present Simple",
            "color": "blue",
            "description": "Z czasownikiem <strong>to be</strong> używamy skróconych form przeczących.",
            "examples": [
                {
                    "en": "Isn't she happy?",
                    "ua": "Czy ona nie jest szczęśliwa?"
                },
                {
                    "en": "Aren't you ready?",
                    "ua": "Czy nie jesteś gotowy?"
                },
                {
                    "en": "Isn't it expensive?",
                    "ua": "Czy to nie jest drogie?"
                },
                {
                    "en": "Aren't they at home?",
                    "ua": "Czy ich nie ma w domu?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "amber",
            "description": "W czasie przeszłym używamy <strong>wasn't</strong> i <strong>weren't</strong>.",
            "examples": [
                {
                    "en": "Wasn't he at work yesterday?",
                    "ua": "Czy on nie był wczoraj w pracy?"
                },
                {
                    "en": "Weren't you tired?",
                    "ua": "Czy nie byłeś zmęczony?"
                },
                {
                    "en": "Wasn't it difficult?",
                    "ua": "Czy to nie było trudne?"
                },
                {
                    "en": "Weren't they happy?",
                    "ua": "Czy oni nie byli szczęśliwi?"
                }
            ]
        },
        {
            "label": "Forma pełna",
            "color": "rose",
            "description": "W stylu bardziej formalnym można użyć pełnej formy, np. <strong>is she not...?</strong>",
            "examples": [
                {
                    "en": "Is she not happy?",
                    "ua": "Czy ona nie jest szczęśliwa?"
                },
                {
                    "en": "Are you not ready?",
                    "ua": "Czy nie jesteś gotowy?"
                }
            ],
            "note": "📌 Forma skrócona brzmi bardziej naturalnie w zwykłej rozmowie."
        }
    ]
}

{
    "title": "4. Pytania przeczące z czasownikami modalnymi",
    "sections": [
        {
            "label": "CAN / COULD",
            "color": "emerald",
            "description": "Z <strong>can</strong> i <strong>could</strong> tworzymy pytania typu <strong>can't / couldn't</strong>.",
            "examples": [
                {
                    "en": "Can't you swim?",
                    "ua": "Czy nie umiesz pływać?"
                },
                {
                    "en": "Couldn't she drive?",
                    "ua": "Czy ona nie umiała prowadzić?"
                },
                {
                    "en": "Couldn't they help us?",
                    "ua": "Czy oni nie mogli nam pomóc?"
                }
            ]
        },
        {
            "label": "WILL / WOULD",
            "color": "sky",
            "description": "Tak samo działają formy <strong>won't</strong> i <strong>wouldn't</strong>.",
            "examples": [
                {
                    "en": "Won't you come?",
                    "ua": "Czy nie przyjdziesz?"
                },
                {
                    "en": "Wouldn't she like it?",
                    "ua": "Czy jej by się to nie spodobało?"
                },
                {
                    "en": "Won't they be late?",
                    "ua": "Czy oni się nie spóźnią?"
                }
            ]
        },
        {
            "label": "SHOULD / MUST / MAY",
            "color": "purple",
            "description": "Pozostałe modale również mogą wystąpić w formie przeczącej.",
            "examples": [
                {
                    "en": "Shouldn't we go?",
                    "ua": "Czy nie powinniśmy iść?"
                },
                {
                    "en": "Shouldn't I wait?",
                    "ua": "Czy nie powinienem poczekać?"
                },
                {
                    "en": "Mustn't we be careful?",
                    "ua": "Czy nie musimy być ostrożni?"
                }
            ],
            "note": "📌 Struktura: <strong>negative modal + subject + base verb</strong>."
        }
    ]
}

{
    "title": "5. Pytania przeczące z innymi czasami",
    "sections": [
        {
            "label": "Present Perfect",
            "color": "blue",
            "description": "W Present Perfect używamy <strong>haven't</strong> albo <strong>hasn't</strong>.",
            "examples": [
                {
                    "en": "Haven't you seen the film?",
                    "ua": "Czy nie widziałeś tego filmu?"
                },
                {
                    "en": "Hasn't she finished yet?",
                    "ua": "Czy ona jeszcze nie skończyła?"
                },
                {
                    "en": "Haven't they arrived?",
                    "ua": "Czy oni jeszcze nie przyjechali?"
                }
            ]
        },
        {
            "label": "Present Continuous",
            "color": "amber",
            "description": "W Present Continuous korzystamy z <strong>isn't</strong> i <strong>aren't</strong>.",
            "examples": [
                {
                    "en": "Aren't you working now?",
                    "ua": "Czy teraz nie pracujesz?"
                },
                {
                    "en": "Isn't she coming?",
                    "ua": "Czy ona nie przychodzi?"
                },
                {
                    "en": "Aren't they playing?",
                    "ua": "Czy oni nie grają?"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "rose",
            "description": "W Past Continuous pojawiają się formy <strong>wasn't</strong> i <strong>weren't</strong> + <strong>-ing</strong>.",
            "examples": [
                {
                    "en": "Weren't you sleeping?",
                    "ua": "Czy nie spałeś?"
                },
                {
                    "en": "Wasn't she studying?",
                    "ua": "Czy ona się nie uczyła?"
                }
            ],
            "note": "📌 W każdym czasie zachowujemy ten sam schemat: przecząca forma czasownika pomocniczego przed podmiotem."
        }
    ]
}

{
    "title": "6. Znaczenie i zastosowanie",
    "sections": [
        {
            "label": "Zaskoczenie",
            "color": "emerald",
            "description": "Pytanie przeczące często pokazuje, że mówiący jest zaskoczony.",
            "examples": [
                {
                    "en": "Don't you like pizza? Everyone likes pizza!",
                    "ua": "Naprawdę nie lubisz pizzy? Przecież większość ludzi ją lubi."
                },
                {
                    "en": "Isn't she coming? I thought she would.",
                    "ua": "To ona jednak nie przyjdzie? Myślałem, że przyjdzie."
                }
            ]
        },
        {
            "label": "Oczekiwanie pozytywnej odpowiedzi",
            "color": "sky",
            "description": "Mówiący często spodziewa się odpowiedzi twierdzącej.",
            "examples": [
                {
                    "en": "Didn't you get my email?",
                    "ua": "To nie dostałeś mojego maila?"
                },
                {
                    "en": "Doesn't he work here?",
                    "ua": "Czy on tu nie pracuje?"
                }
            ]
        },
        {
            "label": "Uprzejma propozycja lub prośba",
            "color": "purple",
            "description": "Pytanie przeczące może też zabrzmieć łagodniej i bardziej uprzejmie.",
            "examples": [
                {
                    "en": "Won't you have some tea?",
                    "ua": "Może napijesz się herbaty?"
                },
                {
                    "en": "Won't you sit down?",
                    "ua": "Może usiądziesz?"
                }
            ]
        },
        {
            "label": "Krytyka albo sarkazm",
            "color": "rose",
            "description": "W zależności od tonu pytanie przeczące może brzmieć krytycznie.",
            "examples": [
                {
                    "en": "Don't you ever listen?",
                    "ua": "Czy ty mnie w ogóle słuchasz?"
                },
                {
                    "en": "Didn't I tell you that already?",
                    "ua": "Czy ja ci już tego nie mówiłem?"
                }
            ],
            "note": "⚠️ Intonacja i kontekst są tu bardzo ważne."
        }
    ]
}

{
    "title": "7. Jak odpowiadać na pytania przeczące",
    "sections": [
        {
            "label": "Odpowiadaj zgodnie z treścią",
            "color": "emerald",
            "description": "Odpowiedź <strong>yes / no</strong> odnosi się do faktu, a nie do samej negacji w pytaniu.",
            "examples": [
                {
                    "en": "Don't you like coffee? — Yes, I do.",
                    "ua": "Czyli: lubię kawę."
                },
                {
                    "en": "Don't you like coffee? — No, I don't.",
                    "ua": "Czyli: nie lubię kawy."
                }
            ]
        },
        {
            "label": "Uważaj na możliwe nieporozumienia",
            "color": "amber",
            "description": "W różnych językach logika odpowiedzi bywa inna, więc w angielskim warto uważać.",
            "examples": [
                {
                    "en": "Don't you know? — Yes, I do.",
                    "ua": "Tak, wiem."
                },
                {
                    "en": "Don't you know? — No, I don't.",
                    "ua": "Nie, nie wiem."
                }
            ]
        },
        {
            "label": "Pełna odpowiedź",
            "color": "sky",
            "description": "Jeśli istnieje ryzyko nieporozumienia, warto odpowiedzieć pełnym zdaniem.",
            "examples": [
                {
                    "en": "Isn't she coming? — No, she isn't coming.",
                    "ua": "Taka odpowiedź jest całkowicie jasna."
                },
                {
                    "en": "Don't you like it? — Yes, I do like it.",
                    "ua": "Pełne zdanie pomaga uniknąć wątpliwości."
                }
            ],
            "note": "📌 Krótkie <strong>yes</strong> i <strong>no</strong> są poprawne, ale pełna odpowiedź bywa bardziej czytelna."
        }
    ]
}

{
    "title": "8. Porównanie zwykłych i przeczących pytań",
    "intro": "Najważniejsze różnice między pytaniem neutralnym a przeczącym:",
    "rows": [
        {
            "en": "Neutral question",
            "ua": "Pytanie neutralne",
            "note": "Do you like coffee? — zwykłe pytanie o fakt"
        },
        {
            "en": "Negative question",
            "ua": "Pytanie przeczące",
            "note": "Don't you like coffee? — zaskoczenie albo oczekiwanie"
        },
        {
            "en": "Emotion",
            "ua": "Emocjonalny wydźwięk",
            "note": "Pytanie przeczące często pokazuje reakcję mówiącego"
        },
        {
            "en": "Expectation",
            "ua": "Oczekiwanie",
            "note": "Mówiący często przewiduje określoną odpowiedź"
        },
        {
            "en": "Answer",
            "ua": "Odpowiedź",
            "note": "Yes / no odnoszą się do treści, nie do samej negacji"
        }
    ],
    "warning": "📌 Pytanie przeczące pyta o fakt, ale jednocześnie zdradza nastawienie mówiącego."
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Odpowiedź zgodnie z formą pytania zamiast zgodnie z faktem.",
            "wrong": "❌ Don't you like it? — Yes, I don't.",
            "right": "✅ <span class=\"font-mono\">Don't you like it? — No, I don't.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zła kolejność słów w pytaniu.",
            "wrong": "❌ You don't like coffee?",
            "right": "✅ <span class=\"font-mono\">Don't you like coffee?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawna forma głównego czasownika.",
            "wrong": "❌ Doesn't she likes it?",
            "right": "✅ <span class=\"font-mono\">Doesn't she like it?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Użycie pytania przeczącego tam, gdzie potrzebne jest pytanie neutralne.",
            "wrong": "❌ Don't you have a pen? (gdy pytasz neutralnie)",
            "right": "✅ <span class=\"font-mono\">Do you have a pen?</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą formę",
    "select_intro": "Wybierz poprawne pytanie przeczące.",
    "selects": [
        {
            "label": "a) Don't you like coffee? / b) Doesn't you like coffee? / c) You don't like coffee?",
            "prompt": "Która forma jest poprawna?"
        },
        {
            "label": "a) Isn't she happy? / b) Doesn't she happy? / c) She isn't happy?",
            "prompt": "Która forma jest poprawna?"
        },
        {
            "label": "a) Can't you swim? / b) Don't you can swim? / c) You can't swim?",
            "prompt": "Która forma jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Ćwiczenie 2. Utwórz pytanie przeczące",
    "input_intro": "Przekształć zwykłe pytanie w pytanie przeczące.",
    "inputs": [
        {
            "before": "Do you know? → ",
            "after": ""
        },
        {
            "before": "Is she coming? → ",
            "after": ""
        },
        {
            "before": "Can they help? → ",
            "after": ""
        },
        {
            "before": "Did you see it? → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu przeczącym.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Doesn't she likes it?",
            "example_target": "Doesn't she like it?"
        },
        {
            "original": "1. Isn't he knows the answer?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Don't she work here?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Yes, I don't.",
            "placeholder": "Popraw odpowiedź"
        }
    ]
}

{
    "title": "Inne lekcje w tej sekcji",
    "items": [
        {
            "label": "Question Forms",
            "current": false
        },
        {
            "label": "Yes / No Questions",
            "current": false
        },
        {
            "label": "Wh-Questions",
            "current": false
        },
        {
            "label": "Answers to Questions",
            "current": false
        },
        {
            "label": "Alternative Questions",
            "current": false
        },
        {
            "label": "Question Tags",
            "current": false
        },
        {
            "label": "Negative Questions",
            "current": true
        }
    ]
}
